const r=$json;
const esc=s=>(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const fmt={feed:'Feed',story:'Historia',reel:'Reel'};
const pubs=r.publicados||[];
const rows=pubs.map(x=>`<tr><td style="padding:7px 10px;color:#8a8a82;font-family:monospace;white-space:nowrap">${x.hora}</td><td style="padding:7px 10px;color:#e8e4dc">${esc(x.titulo)}${x.permalink?` &nbsp;<a href="${x.permalink}" style="color:#ff7700;text-decoration:none">ver &#8599;</a>`:''}</td><td style="padding:7px 10px;color:#ff7700;text-transform:uppercase;font-size:.72rem;letter-spacing:.05em">${fmt[x.formato]||x.formato}</td></tr>`).join('');
const pend=r.pendientes||0;
const pendLine = pend>0 ? `<p style="color:#a5a59c;font-size:.85rem;margin-top:22px">Pendientes de aprobaci&oacute;n: <b style="color:#e8e4dc">${pend}</b> &mdash; <a href="https://panel.clausina.ar" style="color:#ff7700;text-decoration:none">ver el panel &#8599;</a></p>` : '';
const html=`<div style="font-family:Arial,sans-serif;max-width:560px;margin:auto;background:#080806;color:#e8e4dc;padding:32px;border-radius:8px"><div style="font-size:1.6rem;font-weight:900;color:#ff4400;letter-spacing:.05em">CORTAFUEGO</div><p style="color:#a5a59c;font-size:.78rem;letter-spacing:.15em;text-transform:uppercase">Resumen del ${r.dia}</p><p style="font-size:1.05rem">Ayer se ${pubs.length===1?'public&oacute; 1 pieza':'publicaron '+pubs.length+' piezas'}:</p><table style="width:100%;border-collapse:collapse;background:#111110;border-radius:6px;overflow:hidden">${rows}</table>${pendLine}<p style="color:#55554f;font-size:.72rem;margin-top:28px">Aprob&aacute;, rechaz&aacute; o descart&aacute; desde Telegram o el panel.</p></div>`;
return [{json:{subject:`CORTAFUEGO — Ayer se publicó (${pubs.length})`, html, n:pubs.length}}];
